<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Compromiso individual · <?= esc($client['nombre_tercero']) ?></title><link rel="stylesheet" href="<?= base_url('assets/css/app.css') ?>"><style>body{margin:0;background:#f4f6f8;color:#17202d}.wrap{max-width:900px;margin:auto;padding:24px 16px 48px}.legal{background:#fff;border:1px solid #dfe3e8;padding:24px;max-height:58vh;overflow:auto}.legal h1{font-size:1.4rem}.legal h2{font-size:1rem;margin-top:20px}.actions{background:#fff;border:1px solid #dfe3e8;padding:20px;margin-top:14px}.signature{width:100%;height:170px;border:1px dashed #667085;touch-action:none}.btn{margin-top:12px}</style></head><body><main class="wrap"><h1><?= esc($client['nombre_tercero']) ?></h1><?php if(session('error')): ?><div class="alert alert-error"><?= esc(session('error')) ?></div><?php endif; ?><?php if(session('success')): ?><div class="alert alert-success"><?= esc(session('success')) ?></div><?php endif; ?><?php if($success): ?><div class="alert alert-success"><?= esc($confirmation) ?></div><?php else: ?><div id="legal-instance" class="legal"><?= $agreement['instancia_html'] ?></div><section class="actions"><?php if(empty($agreement['vista_at'])): ?><form method="post" action="<?= base_url('confidencialidad/'.$token.'/visualizacion') ?>"><?= csrf_field() ?><button id="confirm-view" class="btn btn-primary" type="submit" disabled>Confirmar lectura completa</button></form><p class="hint">La confirmacion se habilita al llegar al final de la instancia.</p><?php else: ?><form method="post" action="<?= base_url('confidencialidad/'.$token.'/codigo') ?>"><?= csrf_field() ?><button class="btn btn-muted" type="submit">Enviar codigo al correo</button></form><form id="agreement-form" method="post" action="<?= base_url('confidencialidad/'.$token.'/aceptar') ?>"><?= csrf_field() ?><label>Codigo recibido</label><input name="codigo" inputmode="numeric" pattern="[0-9]{6}" maxlength="6" required><label>Firma</label><canvas id="signature" class="signature"></canvas><input type="hidden" id="firma_imagen" name="firma_imagen"><button type="button" id="clear-signature" class="btn btn-muted">Limpiar firma</button><label><input type="checkbox" name="acepto" value="1" required> Lei la instancia completa y acepto este compromiso individual.</label><button class="btn btn-primary" type="submit">Firmar instancia</button></form><?php endif; ?></section><?php endif; ?></main><script>(function(){var legal=document.getElementById('legal-instance'),confirm=document.getElementById('confirm-view');if(legal&&confirm){function reachedEnd(){confirm.disabled=legal.scrollTop+legal.clientHeight<legal.scrollHeight-8}legal.addEventListener('scroll',reachedEnd);reachedEnd()}var c=document.getElementById('signature');if(!c)return;var x=c.getContext('2d'),d=false,dirty=false;function size(){var r=c.getBoundingClientRect();c.width=r.width*devicePixelRatio;c.height=r.height*devicePixelRatio;x=c.getContext('2d');x.scale(devicePixelRatio,devicePixelRatio);x.lineWidth=2;x.lineCap='round'}function p(e){var r=c.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top}}c.addEventListener('pointerdown',function(e){d=true;dirty=true;var q=p(e);x.beginPath();x.moveTo(q.x,q.y)});c.addEventListener('pointermove',function(e){if(!d)return;var q=p(e);x.lineTo(q.x,q.y);x.stroke()});window.addEventListener('pointerup',function(){d=false});document.getElementById('clear-signature').addEventListener('click',function(){x.clearRect(0,0,c.width,c.height);dirty=false});document.getElementById('agreement-form').addEventListener('submit',function(){document.getElementById('firma_imagen').value=dirty?c.toDataURL('image/png'):''});size()})();</script></body></html>
